#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    double fractionalKnapsack(int W, vector<int>& v, vector<int>& w) {
        int n = v.size();
        vector<pair<double, pair<int, int>>> items;
        for (int i = 0; i < n; i++) {
            double ratio = static_cast<double>(v[i]) / w[i];
            items.emplace_back(ratio, make_pair(v[i], w[i]));
        }
        sort(items.begin(), items.end(), [](const auto& a, const auto& b) {
            return a.first > b.first;
        });
        double totalValue = 0.0;
        for (const auto& item : items) {
            if (W >= item.second.second) {
                totalValue += item.second.first;
                W -= item.second.second;
            } else {
                double fraction = static_cast<double>(W) / item.second.second;
                totalValue += item.second.first * fraction;
                break;
            }
        }
        return totalValue;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    int W;
    if (!(cin >> W)) return 0;
    vector<int> v(n), w(n);
    for (int i = 0; i < n; i++) cin >> v[i];
    for (int i = 0; i < n; i++) cin >> w[i];
    Solution sol;
    double ans = sol.fractionalKnapsack(W, v, w);
    cout << fixed << setprecision(6) << ans << "\n";
    return 0;
}
